# Makefile for PAGASA Typhoon Monitoring System

.PHONY: all setup validate status launch docker-build docker-run clean

# Default target
all: setup

# Setup the monitoring system
setup:
	python -m pip install -r requirements.txt
	python -m pip install -r check_requirements.txt
	@echo "✅ Setup complete"

# Validate configuration
validate:
	python validate_config.py

# Check PAGASA website status
status:
	python check_status.py

# Launch the monitor
launch:
	python typhoon_monitor.py

# Docker build
docker-build:
	docker build -t typhoon-monitor .

# Docker run
docker-run:
	docker-compose up -d

# Clean up
clean:
	rm -f last_seen_typhoon.json
	@echo "🧹 Cleaned up state files"

# Help message
help:
	@echo "PAGASA Typhoon Monitoring System Makefile"
	@echo "========================================="
	@echo "make setup      - Install dependencies"
	@echo "make validate   - Validate configuration"
	@echo "make status     - Check PAGASA website status"
	@echo "make launch     - Start monitoring system"
	@echo "make docker-build - Build Docker image"
	@echo "make docker-run - Run with Docker Compose"
	@echo "make clean      - Clean up state files"
	@echo "make help       - Show this help message"

